import React from "react"
import { useStaticQuery, graphql } from "gatsby"
import Project from "./Project"

const Projects = () => {
  const data = useStaticQuery(graphql`
    query {
      stackbox: file(relativePath: { eq: "project-stackbox.png" }) {
        childImageSharp {
          fluid {
            ...GatsbyImageSharpFluid
          }
        }
      }
      asteroid: file(relativePath: { eq: "project-asteroid.png" }) {
        childImageSharp {
          fluid {
            ...GatsbyImageSharpFluid
          }
        }
      }
    }
  `)

  return (
    <div className="projects section" id="projects">
      <div className="section-container">
        <h1>projects</h1>
        <div className="projects-list">
          <Project
            name="stackbox"
            desc="capstone group project"
            github="https://github.com/guava-jay/capstone"
            demo="http://stackbox.herokuapp.com/"
          />
          <Project
            name="asteroid maps"
            desc="graph NASA's near-earth object API"
            github="https://github.com/mendelevich/asteroid-maps"
            demo="http://asteroid-maps.herokuapp.com/"
          />
          <Project
            name="mendelevi.ch"
            desc="(you are here)"
            github="https://github.com/mendelevich/mendelevich.github.io"
          />
          <Project
            className="display"
            name="more to come..."
            desc="always learning & building"
          />
        </div>
      </div>
    </div>
  )
}

export default Projects
